ex_d002.solution:
int sum(List<int> a) {
  var total = 0;
  for (var v in a) {
    total += v;
  }
  return total;
}

ex_d003.solution:
int countEven(List<int> a) {
  var cnt = 0;
  for (var v in a) {
    if (v % 2 == 0) cnt++;
  }
  return cnt;
}

